#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=100005;
int n,a[N],b[N],tr[N];
void update(int x,int y)
{
	for(;x<=n;x+=(x&(-x)))
	{
		tr[x]=max(tr[x],y);
	}
}
int query(int x)
{
	int ans=0;
	for(;x>0;x-=((-x)&x))
	{
		ans=max(ans,tr[x]);
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		b[x]=i;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		a[i]=b[a[i]];
		update(a[i],query(a[i]-1)+1);
	}
	cout<<query(n);
	return 0;
}
